// Inputs from previous node (adjust keys if yours differ)
const {
  doctor_name,
  requested_date,       // "YYYY-MM-DD"
  requested_time,       // "HH:mm"
  doctor_schedule = {}
} = $json;

const booked = doctor_schedule.booked_slots || [];
const working = doctor_schedule.working_hours || {};

const SLOT_MIN = 30;          // slot length in minutes
const MAX_SUGGESTIONS = 5;    // how many to return
const SEARCH_DAYS = 14;       // search up to N days forward
const TIMEZONE = 'Asia/Manila'; // adjust if needed

// ---------- helpers ----------
function toMin(t){ const [h,m]=t.split(':').map(Number); return h*60+m; }
function fmtTime(m){ const h = Math.floor(m/60).toString().padStart(2,'0'); const mm=(m%60).toString().padStart(2,'0'); return `${h}:${mm}`; }
function dayKey(d){
  return d.toLocaleDateString('en-US', { weekday:'long', timeZone: TIMEZONE }).toLowerCase(); // "monday"
}
function toISODate(d){
  const y = d.toLocaleDateString('en-CA', { timeZone: TIMEZONE }); // YYYY-MM-DD
  return y;
}
function parseRange(r){ // "09:00-17:00" → [540, 1020]
  const [s,e] = r.split('-'); return [toMin(s), toMin(e)];
}

// Build fast lookup of booked minutes per date
const bookedMap = new Map();
for (const s of booked) {
  const key = s.date;
  const set = bookedMap.get(key) || new Set();
  set.add(`${s.time}|${s.duration||SLOT_MIN}`);
  bookedMap.set(key, set);
}

// also treat the original requested slot as "booked" to avoid suggesting it again
{
  const set = bookedMap.get(requested_date) || new Set();
  set.add(`${requested_time}|${SLOT_MIN}`);
  bookedMap.set(requested_date, set);
}

// Start search from requested_date (inclusive)
let cursor = new Date(`${requested_date}T00:00:00`);
const out = [];

for (let d=0; d<SEARCH_DAYS && out.length < MAX_SUGGESTIONS; d++) {
  const dateISO = toISODate(cursor);
  const wkKey = dayKey(cursor);                        // e.g. "tuesday"
  const ranges = working[wkKey] || [];                 // e.g. ["09:00-17:00"]
  if (ranges.length) {
    const bookedSet = bookedMap.get(dateISO) || new Set();

    for (const r of ranges) {
      const [startMin, endMin] = parseRange(r);
      for (let m=startMin; m + SLOT_MIN <= endMin && out.length < MAX_SUGGESTIONS; m += SLOT_MIN) {
        const t = fmtTime(m);
        const token = `${t}|${SLOT_MIN}`;
        if (!bookedSet.has(token)) {
          out.push({
            date: dateISO,
            time: t,
            doctor_name,
            appointment_type: "General",
            available: true,
            slot_type: "alternative"
          });
        }
      }
    }
  }
  // next day
  cursor.setDate(cursor.getDate() + 1);
}

// Return merged payload with alternatives
return [
  {
    ...$json,
    alternative_slots: out,
    alternatives_count: out.length,
    original_request_available: false,
    suggestion_generated: true,
    generated_at: new Date().toISOString()
  }
];

// Get error details from input
const errorData = $input.item.json;
const errorType = errorData.error_type;
const originalData = JSON.parse(errorData.failed_data || '{}');

// Define error response templates
const errorTemplates = {
  missing_patient_data: {
    code: 'PATIENT_DATA_MISSING',
    title: 'Patient Information Required',
    message: 'We need your complete information to process your ' +
      'appointment request.',
    user_message: 'Please provide your patient ID, full name, phone ' +
      'number, and email address.',
    severity: 'high'
  },
  missing_appointment_id: {
    code: 'APPOINTMENT_ID_MISSING', 
    title: 'Appointment Reference Missing',
    message: 'Appointment ID is required for modification or ' +
      'cancellation requests.',
    user_message: 'Please provide your appointment confirmation number.',
    severity: 'medium'
  },
  validation_error: {
    code: 'VALIDATION_FAILED',
    title: 'Incomplete Request',
    message: 'Some required information is missing from your ' +
      'appointment request.',
    user_message: 'Please check that you\'ve provided doctor name, ' +
      'preferred date, and time.',
    severity: 'medium'
  },
  availability_error: {
    code: 'SLOT_UNAVAILABLE',
    title: 'Time Slot Not Available', 
    message: 'The requested appointment time is not available.',
    user_message: 'Please choose from the alternative times we\'ve ' +
      'suggested or call our office.',
    severity: 'low'
  },
  system_error: {
    code: 'SYSTEM_ERROR',
    title: 'System Temporarily Unavailable',
    message: 'Our appointment system is temporarily unavailable.',
    user_message: 'Please try again in a few minutes or call our ' +
      'office directly.',
    severity: 'high'
  }
};

// Get error template or use default
const template = errorTemplates[errorType] || errorTemplates.system_error;

// Generate response
const response = {
  error_code: template.code,
  error_title: template.title,
  error_message: template.message,
  user_friendly_message: template.user_message,
  severity: template.severity,
  patient_name: originalData.patient_name || 'Valued Patient',
  patient_contact: originalData.patient_phone || 
    originalData.patient_email || '',
  timestamp: new Date().toISOString(),
  support_phone: '555-DOCTOR',
  support_email: 'appointments@healthcare.com',
  resolution_steps: [
    'Review the information you provided',
    'Ensure all required fields are complete',
    'Try submitting your request again',
    'Contact our office if the problem continues'
  ],
  original_request_id: errorData.error_id,
  retry_possible: template.severity !== 'high'
};

return {
  json: {
    ...errorData,
    ...response
  }
};

